from typing import Any

from fastapi import APIRouter, HTTPException, Request
from pydantic import BaseModel, Field

from backend.self_improver.engine import approve, execute, pending, propose, reject

router = APIRouter(prefix="/self", tags=["Self Improver"])


class ProposalRequest(BaseModel):
    title: str = Field(min_length=3, max_length=200)
    reason: str = Field(min_length=5, max_length=2000)
    steps: list[dict[str, Any]] = Field(min_length=1, max_length=20)


def _guard(request: Request) -> None:
    expected = request.app.state.api_key if hasattr(request.app.state, "api_key") else ""
    if not expected:
        return
    provided = request.headers.get("x-api-key", "").strip()
    if provided != expected:
        raise HTTPException(status_code=401, detail="Unauthorized")


@router.post("/propose")
def propose_route(data: ProposalRequest, request: Request):
    _guard(request)
    return propose(data.title, data.reason, data.steps)


@router.get("/pending")
def pending_route(request: Request):
    _guard(request)
    return pending()


@router.post("/approve/{pid}")
def approve_route(pid: str, request: Request):
    _guard(request)
    ok = approve(pid)
    if not ok:
        raise HTTPException(status_code=404, detail="Proposal not found")
    return {"ok": True}


@router.post("/reject/{pid}")
def reject_route(pid: str, request: Request):
    _guard(request)
    ok = reject(pid)
    if not ok:
        raise HTTPException(status_code=404, detail="Proposal not found")
    return {"ok": True}


@router.post("/execute/{pid}")
def execute_route(pid: str, request: Request):
    _guard(request)
    return execute(pid)

