def _restore(backups: list[tuple[Path, Path]], created: list[Path]) -> None:
    for path in reversed(created):
        try:
            if path.exists():
                path.unlink()
        except Exception:
            pass

    for path, backup_path in reversed(backups):
        try:
            path.parent.mkdir(parents=True, exist_ok=True)
            shutil.copy2(backup_path, path)
        except Exception:
            pass


def execute(pid: str) -> dict[str, Any]:
    d = load()
    p = next((x for x in d if x["id"] == pid), None)

    if not p:
        return {"ok": False, "error": "proposal not found"}
    if p["status"] != "approved":
        return {"ok": False, "error": "not approved"}

    _validate_steps(p.get("steps", []))

    backups: list[tuple[Path, Path]] = []
    created: list[Path] = []
    touched_paths: list[str] = []

    try:
        for s in p["steps"]:
            path = _normalize_path(s["path"])
            touched_paths.append(s["path"])

            if s["action"] == "create_file":
                path.parent.mkdir(parents=True, exist_ok=True)
                if path.exists():
                    b = backup(path)
                    if b:
                        backups.append((path, b))
                else:
                    created.append(path)
                path.write_text(s.get("content", ""), encoding="utf-8")

            elif s["action"] == "edit_file":
                if not path.exists():
                    raise FileNotFoundError(f"missing file: {s['path']}")
                original = path.read_text(encoding="utf-8", errors="ignore")
                find_text = s["find"]
                replace_text = s["replace"]

                if find_text not in original:
                    raise ValueError(f"find text not found in: {s['path']}")

                b = backup(path)
                if b:
                    backups.append((path, b))

                updated = original.replace(find_text, replace_text, 1)
                if updated == original:
                    raise ValueError(f"edit produced no change for: {s['path']}")

                path.write_text(updated, encoding="utf-8")

            elif s["action"] == "delete_file":
                if not path.exists():
                    raise FileNotFoundError(f"missing file: {s['path']}")
                b = backup(path)
                if b:
                    backups.append((path, b))
                path.unlink()

        if not verify():
            raise RuntimeError("verification failed")

        p["status"] = "applied"
        p["applied_at"] = time.time()
        p["result"] = {
            "ok": True,
            "changed_files": touched_paths,
            "backup_count": len(backups),
        }
        save(d)
        return {
            "ok": True,
            "id": pid,
            "status": "applied",
            "changed_files": touched_paths,
            "backup_count": len(backups),
        }
    except Exception as e:
        _restore(backups, created)
        p["status"] = "approved"
        p["last_error"] = str(e)
        p["last_error_at"] = time.time()
        save(d)
        return {"ok": False, "error": str(e), "id": pid}

