def _normalize_job_payload(data: dict) -> dict:
    result = dict(data)
    result.setdefault("checked_at", int(time.time()))

    files = result.get("files")
    if isinstance(files, list):
        normalized_files = []
        for name in files:
            if isinstance(name, str) and name.strip():
                normalized_files.append({
                    "name": name,
                    "url": _build_file_url(name),
                })
        result["files"] = normalized_files
        result["download_ready"] = len(normalized_files) > 0
    else:
        result.setdefault("download_ready", False)

    return result

