                path.parent.mkdir(parents=True, exist_ok=True)
                path.write_text(s.get("content", ""), encoding="utf-8")
                created_files.append(path)

            elif s["action"] == "edit_file":
                if not path.exists():
                    raise Exception(f"missing file: {s['path']}")
                b = backup(path)
                if b:
                    backups.append((path, b))
                txt = path.read_text(encoding="utf-8")
                if s["find"] not in txt:
                    raise Exception(f"find text not found in {s['path']}")
                txt = txt.replace(s["find"], s["replace"], 1)
                path.write_text(txt, encoding="utf-8")

            elif s["action"] == "delete_file":
                if not path.exists():
                    raise Exception(f"missing file: {s['path']}")
                b = backup(path)
                if b:
                    backups.append((path, b))
                path.unlink()

        finished_at = int(time.time())
        p["status"] = "applied"
        p["applied_at"] = finished_at
        save(d)
        execution_log.append({
            "id": pid,
            "title": p.get("title"),
            "status": "applied",
            "started_at": started_at,
            "finished_at": finished_at,
            "steps": p.get("steps", []),
            "backups": [{"path": str(path), "backup": str(backup_path)} for path, backup_path in backups],
            "created_files": [str(path) for path in created_files]
        })
        _save_execution_log(execution_log)
        return {"ok": True, "id": pid, "status": "applied"}

    except Exception as e:
        for path in created_files:
            try:
                if path.exists():
                    path.unlink()
            except Exception:
                pass

        for path, backup_path in reversed(backups):
            try:
                shutil.copy2(backup_path, path)
            except Exception:
                pass

        p["status"] = "approved"
        save(d)
        execution_log.append({
            "id": pid,
            "title": p.get("title"),
            "status": "failed",
            "started_at": started_at,
            "finished_at": int(time.time()),
            "steps": p.get("steps", []),
            "error": str(e)
        })
        _save_execution_log(execution_log)
        return {"ok": False, "id": pid, "error": str(e)}

